class Solution {
    public int addMinimum(String word) {
        int count = 0;
        char[] chars = word.toCharArray();
        int i = 0;
        while (i < chars.length) {
            if (chars[i] == 'a') {
                if (i + 1 < chars.length && chars[i + 1] == 'b') {
                    if (i + 2 < chars.length && chars[i + 2] == 'c') {
                        i += 3;
                    } else {
                        count += 1;
                        i += 2;
                    }
                } else {
                    count += 2;
                    i += 1;
                }
            } else if (chars[i] == 'b') {
                count += 1;
                if (i + 1 < chars.length && chars[i + 1] == 'c') {
                    i += 2;
                } else {
                    count += 1;
                    i += 1;
                }
            } else {
                count += 2;
                i += 1;
            }
        }
        return count;
    }
}
